// Infer service branch from installation name. Fort/USAG/Camp -> Army
// (with Marine Camp exceptions). NAS/NS/Naval Station -> Navy. AFB/SFB
// -> Air Force / Space Force. MCB/MCAS/Marine Corps -> Marine Corps.
// USCG / Coast Guard -> Coast Guard.
function inferBranch(name) {
  const n = String(name || '').toLowerCase();
  if (n.startsWith('uscg') || n.includes('coast guard')) return 'Coast Guard';
  if (n.startsWith('mcb ') || n.startsWith('mcas ') || n.includes('marine corps') ||
      n.startsWith('camp pendleton') || n.startsWith('camp lejeune') ||
      n.startsWith('camp butler') || n.startsWith('camp foster') ||
      n.startsWith('camp hansen') || n.startsWith('camp courtney') ||
      n.startsWith('camp kinser') || n.startsWith('camp schwab')) return 'Marine Corps';
  if (n.includes(' sfb') || n.includes('space force')) return 'Space Force';
  if (n.endsWith(' afb') || n.includes(' afb ') || n.includes('air force') ||
      n.endsWith(' ab') || n.includes('hurlburt') || n.includes('hill ')) return 'Air Force';
  if (n.startsWith('nas ') || n.startsWith('ns ') || n.startsWith('naval ') ||
      n.includes('navy ')) return 'Navy';
  if (n.startsWith('fort ') || n.startsWith('camp ') || n.startsWith('usag ') ||
      n.includes('arsenal') || n.includes('army') || n.startsWith('rock island') ||
      n.startsWith('aberdeen') || n.startsWith('redstone')) return 'Army';
  // Air Force One-Source default for Joint Base entries (almost all
  // joint bases are AF-managed) — narrower than Army for an unknown.
  if (n.startsWith('joint base')) return 'Air Force';
  return 'Department of Defense';
}

// Branch -> official portal where the directory entry's public page
// can be found.
function branchPortalUrl(branch) {
  switch (branch) {
    case 'Army':         return 'https://home.army.mil/';
    case 'Navy':         return 'https://www.cnic.navy.mil/installations.html';
    case 'Marine Corps': return 'https://www.marines.mil/';
    case 'Air Force':    return 'https://www.af.mil/';
    case 'Space Force':  return 'https://www.spaceforce.mil/';
    case 'Coast Guard':  return 'https://www.uscg.mil/';
    default:             return 'https://installations.militaryonesource.mil/';
  }
}

// Build an auto-generated INSTALLATION_DIRECTORY record. All
// placeholder strings point users to authoritative .mil / .gov sources
// so we never display fabricated phone numbers or wait-time guesses.
// Slugify an installation name for the MilitaryINSTALLATIONS deep
// link. The official site uses lowercase, hyphenated, ASCII-only slugs
// (e.g., "Fort Bragg" -> "fort-bragg"). The site is forgiving — if the
// slug is close it redirects to the canonical entry; if it can't
// resolve it lands on the directory home which is still useful.
function militaryInstallationsSlug(name) {
  return String(name || '')
    .toLowerCase()
    .normalize('NFKD')
    .replace(/[̀-ͯ]/g, '')
    .replace(/&/g, ' and ')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '');
}

// Build deep-linked official resource URLs per installation. Sources
// are .mil / .gov only — MilitaryINSTALLATIONS (DoD installation
// directory), TRICARE.mil (medical), DoDEA (overseas schools),
// home.army.mil / cnic.navy.mil / marines.mil / af.mil / spaceforce.mil
// / uscg.mil (branch portals), defensetravel.mil (BAH/OHA), and
// installations.militaryonesource.mil for the family-readiness side.
function officialInstallationLinks(name, branch, isOconus, zip) {
  const slug = militaryInstallationsSlug(name);
  const ev = encodeURIComponent;
  return {
    directory: `https://installations.militaryonesource.mil/in-depth-overview/${slug}`,
    branchPortal: branchPortalUrl(branch),
    tricareFindCare: zip
      ? `https://www.tricare.mil/FindDoctor?zip=${ev(zip)}`
      : 'https://www.tricare.mil/FindDoctor',
    tricareEnroll: 'https://www.tricare.mil/Resources/Enrollment',
    bahLookup: isOconus
      ? 'https://www.travel.dod.mil/Allowances/Overseas-Housing-Allowance/'
      : 'https://www.travel.dod.mil/Allowances/Basic-Allowance-for-Housing/BAH-Rate-Lookup/',
    dodea: 'https://www.dodea.edu/students-parents/index.cfm',
    housingOffice: `https://installations.militaryonesource.mil/in-depth-overview/${slug}/housing`,
    schoolsTab: `https://installations.militaryonesource.mil/in-depth-overview/${slug}/schools`,
    contactsTab: `https://installations.militaryonesource.mil/in-depth-overview/${slug}/contacts`,
    googleSearch: `https://www.google.com/maps/search/?api=1&query=${ev(name)}`,
  };
}

function autoGenerateDirectoryEntry(name) {
  const market = INSTALLATION_MARKETS[name];
  if (!market) return null;
  const stateRaw = String(market.state || '').trim();
  const stateUp = stateRaw.toUpperCase();
  const isOconus = !(stateUp.length === 2 && (
    TRICARE_REGION_BY_STATE[stateUp] || ['PR','GU','VI','MP','AS','DC'].includes(stateUp)
  ));
  const branch = inferBranch(name);
  const tricareRegion = isOconus
    ? 'Overseas (TOP)'
    : (TRICARE_REGION_BY_STATE[stateUp] || 'Verify on tricare.mil');
  const officialPortal = branchPortalUrl(branch);
  const zip = String(market.postal || market.zip || '').replace(/[^0-9-]/g, '').slice(0, 10);
  const links = officialInstallationLinks(name, branch, isOconus, zip);

  return {
    state: stateRaw,
    branch,
    city: market.city || '',
    country: market.country || (isOconus ? '' : 'United States'),
    postal: zip,
    oconus: isOconus,
    autoGenerated: true,
    // Per-field source labels let the UI tag each value with the
    // .mil/.gov origin so users can verify.
    sources: links,
    housing: {
      waitTime: 'Verify with installation housing office',
      waitTimeSource: links.housingOffice,
      onPostUnits: isOconus
        ? 'Government-owned (garrison) housing — coordinate via gaining unit'
        : 'Privatized housing partner — verify on installation page',
      onPostUnitsSource: links.housingOffice,
      offPostNotes: isOconus
        ? 'Overseas Housing Allowance (OHA) applies. Off-post is country-specific; coordinate with the gaining unit housing office before signing a lease.'
        : 'Use the BAH calculator at travel.dod.mil to plan budget. Local rental market varies — verify neighborhoods, school zones, and commute times before signing.',
      offPostNotesSource: links.bahLookup,
    },
    tricare: {
      region: tricareRegion,
      regionSource: 'https://www.tricare.mil/Plans/Eligibility/RegionsOfTRICARE',
      mtf: zip
        ? `Find the nearest MTF, civilian network provider, and pharmacy via tricare.mil Find a Doctor for ZIP ${zip}`
        : 'Search tricare.mil Find a Doctor for the gaining installation ZIP',
      mtfSource: links.tricareFindCare,
      phone: '1-800-TRICARE (1-800-874-2273)',
      primeAvailable: true,
      selectAvailable: !isOconus, // Select is CONUS-only; OCONUS uses TOP Prime/Select Overseas
      enrollSource: links.tricareEnroll,
    },
    schools: {
      district: isOconus
        ? 'DoDEA (Department of Defense Education Activity)'
        : 'Verify local district via the MilitaryINSTALLATIONS schools tab',
      districtSource: isOconus ? links.dodea : links.schoolsTab,
      rating: null,
      dodea: isOconus,
      dodealabel: isOconus ? 'DoDEA school — verify on dodea.edu' : null,
      liaison: 'Contact gaining installation School Liaison Officer (SLO) via installation page',
      liaisonSource: links.schoolsTab,
    },
    contacts: {
      housing: 'See installation housing office',
      housingSource: links.housingOffice,
      transportation: 'See installation TMO',
      transportationSource: links.contactsTab,
      finance: 'See installation finance office',
      financeSource: links.contactsTab,
      acs: isOconus ? 'See gaining unit Family Support office' : 'See installation ACS / Airman & Family Readiness office',
      acsSource: links.contactsTab,
      legal: 'See installation legal assistance office',
      legalSource: 'https://legalassistance.law.af.mil/',
    },
    website: officialPortal,
    militaryInstallationsUrl: links.directory,
    mapUrl: links.googleSearch,
  };
}

